+		runStatus: finalization.applied ? finalization.runStatus : "not_applied",
+		attemptStatus: finalization.applied ? finalization.attemptStatus : "not_applied",
+		verifiedPullRequest: handoff.ok ? handoff.pullRequest : null,
+	});
