function globToRegex(pattern: string): string {
	let i = 0;
	let output = "";

	while (i < pattern.length) {
		const char = pattern[i];
		if (char === "*") {
			if (pattern[i + 1] === "*") {
				output += ".*";
				i += 2;
				continue;
			}
			output += "[^/]*";
			i += 1;
			continue;
		}

		if (char === "?") {
			output += "[^/]";
			i += 1;
			continue;
		}

		if ("+^$.()|{}[]\\".includes(char)) {
			output += `\\${char}`;
			i += 1;
			continue;
		}

		output += char;
		i += 1;
	}

	return output;
}

